## Usage Example

```rust
use crate::ui::{context::OutputContext, icons::Icons};

fn print_worker_status(name: &str, healthy: bool) {
    let ctx = OutputContext::detect();
    let icon = if healthy {
        Icons::check(ctx)
    } else {
        Icons::cross(ctx)
    };
    eprintln!("  {} {}", icon, name);
}
```

## Testing

```rust
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_icons_with_unicode() {
        let ctx = OutputContext::Interactive; // Assume unicode support

        // These should return Unicode characters
        assert!(Icons::check(ctx).len() > 1 || Icons::check(ctx) == "✓");
    }

    #[test]
    fn test_icons_fallback() {
        let ctx = OutputContext::Plain; // No unicode

        // These should return ASCII fallbacks
        assert!(Icons::check(ctx).chars().all(|c| c.is_ascii()));
        assert!(Icons::cross(ctx).chars().all(|c| c.is_ascii()));
    }

    #[test]
    fn test_all_icons_return_non_empty() {
        let ctx = OutputContext::Interactive;

        assert!(!Icons::check(ctx).is_empty());
        assert!(!Icons::cross(ctx).is_empty());
        assert!(!Icons::warning(ctx).is_empty());
        // ... all icons
    }
}
```

